local OOOOO0OOO='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
local function OO00O0000(b)
    b=b:gsub('%s+','')
    b=b:gsub('[^'..OOOOO0OOO..'=]','')
    return (b:gsub('.', function(x)
        if x=='=' then return '' end
        local r,f='',(OOOOO0OOO:find(x,1,true)-1)
        for i=6,1,-1 do r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0') end
        return r
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?', function(x)
        if #x~=8 then return '' end
        local c=0
        for i=1,8 do if x:sub(i,i)=='1' then c=c+2^(8-i) end end
        return string.char(c)
    end))
end
local OO0OOOO00=OO00O0000(OO000OOOO)
local OOOOO0000=(bit32 and bit32.bxor) or function(a,b) return a ~ b end
local OOOOOOOO0={}
for O0O0OO000=1,#OO0OOOO00 do
    OOOOOOOO0[O0O0OO000]=string.char(OOOOO0000(OO0OOOO00:byte(O0O0OO000),OO00O00OO))
end
